verification.proof_script:
from qiskit.quantum_info import Statevector, SparsePauliOp
O = SparsePauliOp.from_list([("ZZ", 1.0), ("XX", 0.5)])
val = complex(Statevector.from_label("00").expectation_value(O))
claims = {"D": 1.0, "A": 1.5, "B": 0.0, "C": 0.5}
evidence = {}
proven = []
for k, c in claims.items():
    match = bool(abs(val - c) < 1e-9)
    evidence[k] = f"<00|O|00> = {val.real:.4f}; option {k} claims {c} -> match={match}"
    if match:
        proven.append(k)
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"expectation": val.real}})
